// Router: input from trigger or loop recursion (Phase 6: session_start_time, iteration_history)
const raw = $input.first().json;
const fromWebhook = !!raw.body;
const input = raw.body || raw;
if (!input) return [{ json: { error: 'No input' } }];
const payload = typeof input === 'object' ? { ...input } : { message_text: String(input) };
payload.trigger_source = fromWebhook ? 'webhook' : 'executeWorkflow';
payload.goal = payload.goal || payload.message_text || payload.text || '';
payload.iteration = typeof payload.iteration === 'number' ? payload.iteration : 0;
if (payload.iteration === 0) {
  payload.session_start_time = Math.floor(Date.now() / 1000);
  payload.iteration_history = [];
} else {
  payload.session_start_time = payload.session_start_time || Math.floor(Date.now() / 1000);
  payload.iteration_history = Array.isArray(payload.iteration_history) ? payload.iteration_history : [];
}
return [{ json: payload }];

// Intent classifier: keyword-based mapping to plan intents
const ctx = $input.item.json;
const msg = ctx.message_text || ctx.text || ctx.message || ctx.next_prompt || '';
const lower = msg.toLowerCase();
let intent = 'casual_chat';
if (/\b(status|health|check|running|up|down)\b/.test(lower)) intent = 'status_query';
else if (/\b(task|todo|asana|create task)\b/.test(lower)) intent = 'task_creation';
else if (/\b(code|run|execute|script|sandbox)\b/.test(lower)) intent = 'code_request';
else if (/\b(search|find|lookup|mindex|species|fungus)\b/.test(lower)) intent = 'info_retrieval';
else if (/\b(vm|proxmox|restart|deploy|infrastructure)\b/.test(lower)) intent = 'infrastructure_action';
else if (/\b(calendar|schedule|meeting|book)\b/.test(lower)) intent = 'scheduling';
else if (/\b(file|upload|download|document)\b/.test(lower)) intent = 'file_operation';

return [{ json: { ...ctx, intent, message_text: msg || ctx.message_text } }];

// Prepare evaluate-task-completion request body (Phase 6: session_start_time, tokens_used, iteration_history)
const ctx = $('Intent Classifier').first().json;
const mas = $input.item.json;
const result = mas.response_text || mas.message || mas.response || (mas.error ? String(mas.error) : JSON.stringify(mas));
const session_start_time = ctx.session_start_time || Date.now();
const iteration_history = Array.isArray(ctx.iteration_history) ? ctx.iteration_history.slice(-3) : [];
return [{ json: {
  goal: ctx.goal || ctx.message_text,
  result,
  iteration: ctx.iteration || 0,
  max_iterations: 5,
  session_start_time,
  tokens_used: ctx.tokens_used || 0,
  iteration_history,
  _ctx: ctx,
  _response_text: result
} }];

// Merge evaluate result with context for branching
const evalOut = $input.item.json;
const prep = $('Prepare Evaluate').first().json;
const ctx = prep._ctx || {};
const responseText = prep._response_text || '';
return [{ json: { ...ctx, ...evalOut, response_text: responseText } }];

// Format for response router (receives merged data from If Complete)
const d = $input.item.json;
return [{
  json: {
    platform_source: d.platform_source || 'slack',
    channel_id: d.channel_id || null,
    thread_id: d.thread_id || null,
    response_text: d.response_text || '',
    attachments: [],
    sender_id: d.sender_id,
    intent: d.intent,
    trigger_source: d.trigger_source || 'executeWorkflow'
  }
}];

// Prepare loop payload for next iteration (Phase 6: accumulate iteration_history for duplicate detection)
const m = $input.item.json;
const nextPrompt = m.next_prompt || m.message_text;
const prevHistory = Array.isArray(m.iteration_history) ? m.iteration_history : [];
const newEntry = { intent: m.intent, prompt: m.message_text || m.goal, result: m.response_text || m.result || '' };
const iteration_history = [...prevHistory, newEntry].slice(-3);
const base = { ...m, trigger_source: 'executeWorkflow', iteration: (m.iteration || 0) + 1, session_start_time: m.session_start_time, iteration_history };
if (!nextPrompt) return [{ json: { ...base, message_text: 'Continue from previous result.' } }];
return [{ json: { ...base, message_text: nextPrompt, next_prompt: nextPrompt, goal: m.goal } }];
